const SCRIPT = "        // Sticky nav shadow\r\n        const nav = document.getElementById('mainNav');\r\n        window.addEventListener('scroll', () => {\r\n            nav.classList.toggle('scrolled', window.scrollY > 20);\r\n        });\r\n\r\n        // Reveal on scroll\r\n        const reveals = document.querySelectorAll('.reveal');\r\n        const observer = new IntersectionObserver((entries) => {\r\n            entries.forEach(entry => {\r\n                if (entry.isIntersecting) {\r\n                    entry.target.classList.add('visible');\r\n                    // stagger children slightly\r\n                    const children = entry.target.querySelectorAll('.service-card, .step-item, .reason-item, .metric-card, .testi-card, .pricing-card, .tech-card, .portfolio-card');\r\n                    children.forEach((child, i) => {\r\n                        child.style.transitionDelay = `${i * 0.06}s`;\r\n                        child.style.opacity = '0';\r\n                        child.style.transform = 'translateY(16px)';\r\n                        child.style.transition = 'opacity 0.5s ease, transform 0.5s ease';\r\n                        setTimeout(() => {\r\n                            child.style.opacity = '1';\r\n                            child.style.transform = 'translateY(0)';\r\n                        }, 80 + i * 60);\r\n                    });\r\n                }\r\n            });\r\n        }, { threshold: 0.12 });\r\n        reveals.forEach(el => observer.observe(el));\r\n\r\n        // Parallax on hero visual (subtle mouse movement)\r\n        const heroRight = document.querySelector('.hero-right');\r\n        document.addEventListener('mousemove', (e) => {\r\n            if (!heroRight) return;\r\n            const cx = window.innerWidth / 2;\r\n            const cy = window.innerHeight / 2;\r\n            const dx = (e.clientX - cx) / cx;\r\n            const dy = (e.clientY - cy) / cy;\r\n            const terminal = document.querySelector('.vis-terminal');\r\n            const analytics = document.querySelector('.vis-analytics');\r\n            const status = document.querySelector('.vis-status');\r\n            const badge = document.querySelector('.vis-badge');\r\n            if (terminal) terminal.style.transform = `translateY(${dy * -6}px) translateX(${dx * -4}px)`;\r\n            if (analytics) analytics.style.transform = `translateY(${dy * 8}px) translateX(${dx * 6}px)`;\r\n            if (status) status.style.transform = `translateY(${dy * -10}px) translateX(${dx * 8}px)`;\r\n            if (badge) badge.style.transform = `translateY(${dy * 12}px) translateX(${dx * -6}px)`;\r\n        });\r\n\r\n        // Animate progress bars on scroll\r\n        const progressFills = document.querySelectorAll('.progress-fill');\r\n        const progressObserver = new IntersectionObserver((entries) => {\r\n            entries.forEach(entry => {\r\n                if (entry.isIntersecting) {\r\n                    entry.target.style.width = entry.target.getAttribute('style').match(/\\d+%/)?.[0] || '0%';\r\n                }\r\n            });\r\n        }, { threshold: 0.5 });\r\n        progressFills.forEach(fill => {\r\n            const targetWidth = fill.style.width;\r\n            fill.style.width = '0%';\r\n            fill.setAttribute('data-width', targetWidth);\r\n            progressObserver.observe(fill);\r\n        });\r\n        // Fix: trigger on first intersection\r\n        const howObserver = new IntersectionObserver((entries) => {\r\n            entries.forEach(entry => {\r\n                if (entry.isIntersecting) {\r\n                    entry.target.querySelectorAll('.progress-fill').forEach(fill => {\r\n                        const w = fill.getAttribute('data-width');\r\n                        if (w) fill.style.width = w;\r\n                    });\r\n                }\r\n            });\r\n        }, { threshold: 0.2 });\r\n        document.querySelectorAll('.how-visual').forEach(el => howObserver.observe(el));\r\n    ";

